#!/usr/bin/env bash
# Generated by pipeline — do not edit manually
# Site: Site Name | http://localhost:8083

wp() { command wp --allow-root "$@"; }

# Patch wp-config.php for HTTPS proxy (Nginx Proxy Manager)
if ! grep -q "HTTP_X_FORWARDED_PROTO" wp-config.php; then
    sed -i "2i // Proxy SSL Fix\nif (isset(\$_SERVER['HTTP_X_FORWARDED_PROTO']) && \$_SERVER['HTTP_X_FORWARDED_PROTO'] === 'https') { \$_SERVER['HTTPS'] = 'on'; }\n" wp-config.php
fi

if [ ! -f wp-config.php ]; then
    echo "Error: run this script from the WordPress root directory!"
    exit 1
fi

SITE_URL="http://localhost:8083"
SITE_TITLE="Site Name"
ADMIN_USER="admin"
ADMIN_EMAIL="admin@domen.com"
THEME_SLUG="utheme"
WP_LANG="en_US"

ADMIN_PASS=$(tr -dc 'a-zA-Z0-9!@#$%^&*()_+=-' < /dev/urandom | head -c 30)

echo "--- WP Auto-Setup: $SITE_TITLE ---"

# ===========================================================================
# 1. INSTALL WORDPRESS

wp core install \
    --url="$SITE_URL" \
    --title="Initial Setup" \
    --admin_user="$ADMIN_USER" \
    --admin_password="$ADMIN_PASS" \
    --admin_email="$ADMIN_EMAIL" \
    --skip-email

wp language core install $WP_LANG --activate
echo "Language set to $WP_LANG."

# ===========================================================================
# 2. ADMIN USER

FIRST_NAME="Editorial Team"
LAST_NAME="«$SITE_TITLE»"
DISPLAY_NAME="$FIRST_NAME $LAST_NAME"

if wp user get "$ADMIN_USER" > /dev/null 2>&1; then
    wp user update "$ADMIN_USER" \
        --user_pass="$ADMIN_PASS" \
        --role=administrator \
        --display_name="$DISPLAY_NAME" \
        --first_name="$FIRST_NAME" \
        --last_name="$LAST_NAME"
else
    wp user create "$ADMIN_USER" "$ADMIN_EMAIL" \
        --user_pass="$ADMIN_PASS" \
        --role=administrator \
        --display_name="$DISPLAY_NAME" \
        --first_name="$FIRST_NAME" \
        --last_name="$LAST_NAME"
fi

ADMIN_ID=$(wp user get "$ADMIN_USER" --field=ID)
wp user update 1 --locale=en_US
echo "Admin user ready (ID: $ADMIN_ID)."

# ===========================================================================
# 3. THEME

wp theme activate $THEME_SLUG
wp theme list --status=inactive --field=name | while read -r _theme; do wp theme delete "$_theme"; done
echo "Theme '$THEME_SLUG' activated."

# ===========================================================================
# 4. CLEANUP DEFAULT CONTENT

wp post delete $(wp post list --post_type=post,page --format=ids) --force
wp eval "global \$wpdb;
    \$wpdb->query(\"TRUNCATE TABLE {\$wpdb->prefix}posts\");
    \$wpdb->query(\"TRUNCATE TABLE {\$wpdb->prefix}postmeta\");
    \$wpdb->query(\"TRUNCATE TABLE {\$wpdb->prefix}terms\");
    \$wpdb->query(\"TRUNCATE TABLE {\$wpdb->prefix}term_taxonomy\");
    \$wpdb->query(\"TRUNCATE TABLE {\$wpdb->prefix}term_relationships\");"
echo "Default content removed."

# ===========================================================================
# 5. SETTINGS

wp eval "
global \$wp_rewrite;
update_option('blogname', base64_decode('U2l0ZSBOYW1l'));
\$wp_rewrite->set_permalink_structure('/%postname%/');
\$wp_rewrite->flush_rules(true);
update_option('default_pingback_flag', 0);
update_option('default_ping_status', 'closed');
update_option('default_comment_status', 'closed');
update_option('require_name_email', 1);
update_option('comment_registration', 1);
update_option('close_comments_for_old_posts', 1);
update_option('thread_comments', 1);
update_option('thread_comments_depth', 5);
update_option('page_comments', 1);
update_option('comments_per_page', 50);
update_option('default_comments_page', 'newest');
update_option('moderation_notify', 0);
update_option('comments_notify', 0);
update_option('comment_moderation', 1);
update_option('comment_whitelist', 1);
update_option('uploads_use_yearmonth_folders', 0);
update_user_meta($ADMIN_ID, 'edit_post_per_page', 200);
update_user_meta($ADMIN_ID, 'edit_page_per_page', 200);
"
echo "Settings applied."

# ===========================================================================
# 6. CATEGORIES

wp eval "
wp_insert_term('Utility Pages', 'category');
wp_insert_term('page+5', 'category');
wp_insert_term('page+30', 'category');
wp_insert_term('news', 'category');
"
echo "Categories created."

# ===========================================================================
# 7. MEDIA IMPORT
# Медиа импортируются ДО создания страниц, чтобы знать attachment ID и URL
# для замены плейсхолдеров %%IMGID:file.webp%% и %%IMGSRC:file.webp%% в .wp файлах

echo "Importing media from /tmp/staging/images/ ..."
declare -A MEDIA_IDS   # filename → attachment_id
declare -A MEDIA_URLS  # filename → public URL

while IFS=$'\t' read -r _f1 _f2 _f3; do
    if [ "$_f1" = "WARN" ]; then
        echo "  WARN: failed to import $_f2"
    else
        MEDIA_IDS["$_f1"]=$_f2
        MEDIA_URLS["$_f1"]=$_f3
        echo "  $_f1 → ID $_f2"
    fi
done < <(wp eval "
ob_start();
require_once ABSPATH . 'wp-admin/includes/media.php';
require_once ABSPATH . 'wp-admin/includes/file.php';
require_once ABSPATH . 'wp-admin/includes/image.php';
\$results = [];
foreach (glob('/tmp/staging/images/*') as \$file) {
    if (!is_file(\$file)) continue;
    \$fname = basename(\$file);
    \$arr   = ['name' => \$fname, 'tmp_name' => \$file];
    \$id    = media_handle_sideload(\$arr, 0);
    if (is_wp_error(\$id)) {
        \$results[] = 'WARN' . chr(9) . \$fname . chr(9) . '';
        continue;
    }
    \$results[] = \$fname . chr(9) . \$id . chr(9) . wp_get_attachment_url(\$id);
}
ob_end_clean();
echo implode(chr(10), \$results) . chr(10);
" 2>/dev/null)

if [ -n "${MEDIA_IDS[favicon.png]}" ]; then
    wp option update site_icon ${MEDIA_IDS[favicon.png]}
    echo "  Favicon set (ID: ${MEDIA_IDS[favicon.png]})"
fi
if [ -n "${MEDIA_IDS[logo.webp]}" ]; then
    wp eval "set_theme_mod('custom_logo', ${MEDIA_IDS[logo.webp]});"
    echo "  Logo set (ID: ${MEDIA_IDS[logo.webp]})"
fi

# Заменяем плейсхолдеры в .wp файлах реальными ID и URL
echo "Resolving image placeholders in .wp files..."
for page_file in /tmp/staging/pages/*.wp; do
    [ -f "$page_file" ] || continue
    for fname in "${!MEDIA_IDS[@]}"; do
        img_id=${MEDIA_IDS[$fname]}
        img_url=${MEDIA_URLS[$fname]}
        sed -i "s@%%IMGID:${fname}%%@${img_id}@g" "$page_file"
        sed -i "s@%%IMGSRC:${fname}%%@${img_url}@g" "$page_file"
    done
done
echo "Placeholders resolved."

# ===========================================================================
# 8. PAGES
# Каждая страница создаётся одним wp eval: wp_insert_post + мета + категории.
# ob_start/ob_end_clean подавляет любой побочный вывод WP; echo $id — единственный stdout.
# Текстовые данные передаются через base64, избегая конфликтов bash/PHP экранирования.

declare -A PAGE_IDS

# --- index ---
PAGE_ID=$(wp eval "
ob_start();
\$id = wp_insert_post([
    'post_type'     => 'page',
    'post_title'    => base64_decode('V29ybGQgQ3VwIDIwMjYgQmV0dGluZyDigJQgT2RkcywgR3JvdXBzICYgUHJlZGljdGlvbnMgfCBLaWNrT2Rkcw=='),
    'post_name'     => 'index',
    'post_status'   => 'publish',
    'post_content'  => file_get_contents('/tmp/staging/pages/index.wp'),
    'page_template' => 'page.php',
    'post_author'   => $ADMIN_ID,
]);
update_post_meta(\$id, '_thumbnail_id', ${MEDIA_IDS[hero-stadium-world-cup.webp]});
update_post_meta(\$id, '_custom_seo_title', base64_decode('V29ybGQgQ3VwIDIwMjYgQmV0dGluZyDigJQgT2RkcywgR3JvdXBzICYgUHJlZGljdGlvbnMgfCBLaWNrT2Rkcw=='));
update_post_meta(\$id, '_custom_seo_headline', base64_decode('V29ybGQgQ3VwIDIwMjYgQmV0dGluZyDigJQgT2RkcywgR3JvdXBzICYgUHJlZGljdGlvbnMgfCBLaWNrT2Rkcw=='));
update_post_meta(\$id, '_custom_seo_desc', base64_decode('WW91ciBjb21wbGV0ZSBXb3JsZCBDdXAgMjAyNiBiZXR0aW5nIGh1Yi4gT2RkcywgZ3JvdXAgYW5hbHlzaXMsIEFsbCBXaGl0ZXMgY292ZXJhZ2UsIGFuZCBleHBlcnQgcGlja3MgZnJvbSBhIHNlbmlvciBmb290YmFsbCBiZXR0aW5nIGFuYWx5c3Qu'));
ob_end_clean();
echo \$id;
" 2>/dev/null)
PAGE_IDS[index]=$PAGE_ID
echo "  Created 'index' (ID: $PAGE_ID)"

